--
DROP VIEW IF EXISTS "active_appointments";

CREATE VIEW "active_appointments" AS SELECT "current_appointments"."id" AS "id", "current_appointments"."doctorSpecialization" AS "doctorSpecialization", "current_appointments"."doctorId" AS "doctorId", "current_appointments"."userId" AS "userId", "current_appointments"."patientId" AS "patientId", "current_appointments"."consultancyFees" AS "consultancyFees", "current_appointments"."appointmentDate" AS "appointmentDate", "current_appointments"."appointmentTime" AS "appointmentTime", "current_appointments"."postingDate" AS "postingDate", "current_appointments"."userStatus" AS "userStatus", "current_appointments"."doctorStatus" AS "doctorStatus", "current_appointments"."visitStatus" AS "visitStatus", "current_appointments"."checkInTime" AS "checkInTime", "current_appointments"."checkOutTime" AS "checkOutTime", "current_appointments"."prescription" AS "prescription", "current_appointments"."paymentStatus" AS "paymentStatus", "current_appointments"."paymentRef" AS "paymentRef", "current_appointments"."paidAt" AS "paidAt", "current_appointments"."appointmentType" AS "appointmentType", "current_appointments"."paymentOption" AS "paymentOption", "current_appointments"."updationDate" AS "updationDate" FROM "current_appointments" WHERE "current_appointments"."userStatus" = 1 AND "current_appointments"."doctorStatus" = 1 AND coalesce("current_appointments"."visitStatus",'Scheduled') in ('Scheduled','Checked In')  ;

-- --------------------------------------------------------

--
-- Structure for view "completed_appointments"
--
DROP VIEW IF EXISTS "completed_appointments";

CREATE VIEW "completed_appointments" AS SELECT "past_appointments"."id" AS "id", "past_appointments"."doctorSpecialization" AS "doctorSpecialization", "past_appointments"."doctorId" AS "doctorId", "past_appointments"."userId" AS "userId", "past_appointments"."patientId" AS "patientId", "past_appointments"."consultancyFees" AS "consultancyFees", "past_appointments"."appointmentDate" AS "appointmentDate", "past_appointments"."appointmentTime" AS "appointmentTime", "past_appointments"."postingDate" AS "postingDate", "past_appointments"."userStatus" AS "userStatus", "past_appointments"."doctorStatus" AS "doctorStatus", "past_appointments"."visitStatus" AS "visitStatus", "past_appointments"."checkInTime" AS "checkInTime", "past_appointments"."checkOutTime" AS "checkOutTime", "past_appointments"."prescription" AS "prescription", "past_appointments"."paymentStatus" AS "paymentStatus", "past_appointments"."paymentRef" AS "paymentRef", "past_appointments"."paidAt" AS "paidAt", "past_appointments"."appointmentType" AS "appointmentType", "past_appointments"."updationDate" AS "updationDate" FROM "past_appointments" WHERE "past_appointments"."visitStatus" in ('Completed','Cancelled') OR "past_appointments"."userStatus" = 0 OR "past_appointments"."doctorStatus" = 0  ;

-- --------------------------------------------------------

--
-- Structure for view "view_current_appointments"
--
DROP VIEW IF EXISTS "view_current_appointments";

CREATE VIEW "view_current_appointments" AS SELECT "ca"."id" AS "id", "ca"."doctorSpecialization" AS "doctorSpecialization", "ca"."doctorId" AS "doctorId", "ca"."userId" AS "userId", "ca"."patientId" AS "patientId", "ca"."consultancyFees" AS "consultancyFees", "ca"."appointmentDate" AS "appointmentDate", "ca"."appointmentTime" AS "appointmentTime", "ca"."postingDate" AS "postingDate", "ca"."userStatus" AS "userStatus", "ca"."doctorStatus" AS "doctorStatus", "ca"."visitStatus" AS "visitStatus", "ca"."checkInTime" AS "checkInTime", "ca"."checkOutTime" AS "checkOutTime", "ca"."prescription" AS "prescription", "ca"."paymentStatus" AS "paymentStatus", "ca"."paymentRef" AS "paymentRef", "ca"."paidAt" AS "paidAt", "ca"."appointmentType" AS "appointmentType", "ca"."paymentOption" AS "paymentOption", "u"."fullName" AS "userName", "u"."email" AS "userEmail", "d"."doctorName" AS "doctorName" FROM (("current_appointments" "ca" left join "users" "u" on("ca"."userId" = "u"."id")) left join "doctors" "d" on("ca"."doctorId" = "d"."id"))  ;

